function generateVenueMaterial(templateKey, venueName, venueCity, qrUrl, brandColor) {
  let html = VENUE_MATERIAL_TEMPLATES[templateKey];

  // Substitute venue name and city
  html = html.split('{{VENUE_NAME}}').join(venueName || 'Your Venue');
  html = html.split('{{VENUE_CITY}}').join(venueCity || '');

  // Substitute QR code — use Google Charts API for real QR
  const qrSrc = qrUrl
    ? `https://api.qrserver.com/v1/create-qr-code/?size=200x200&bgcolor=F5EDE0&color=2A0E18&data=${encodeURIComponent(qrUrl)}`
    : null;

  const qrImgHtml = qrSrc
    ? `<img src="${qrSrc}" style="width:100%;height:100%;object-fit:contain"/>`
    : `<div class="qr-placeholder">QR code<br>goes here</div>`;

  html = html.split('{{QR_IMAGE}}').join(qrImgHtml);

  // Apply brand color if provided
  if (brandColor && brandColor !== '#4A0F1E') {
    html = html.replace(/var\(--wine\)/g, brandColor)
               .replace(/var\(--wine-mid\)/g, brandColor)
               .replace(/#4A0F1E/g, brandColor)
               .replace(/#6B1A2E/g, brandColor);
  }

  return html;
}

function openVenueMaterial(templateKey, venueName, venueCity, qrUrl, brandColor) {
  const html = generateVenueMaterial(templateKey, venueName, venueCity, qrUrl, brandColor);
  const blob = new Blob([html], { type: 'text/html' });
  const url = URL.createObjectURL(blob);
  const win = window.open(url, '_blank');
  if (win) win.addEventListener('load', () => { setTimeout(() => win.print(), 600); });
}

function downloadVenueMaterial(templateKey, venueName, venueCity, qrUrl, brandColor) {
  const html = generateVenueMaterial(templateKey, venueName, venueCity, qrUrl, brandColor);
  const blob = new Blob([html], { type: 'text/html' });
  const a = document.createElement('a');
  a.href = URL.createObjectURL(blob);
  a.download = `cellartrek-${templateKey}-${(venueName||'venue').replace(/[^a-z0-9]/gi,'_').toLowerCase()}.html`;
  a.click();
}
